Java-like implementation that matches the described API and provides a utility to hash the contents of a file in memory:

public class Sha256Hash implements Comparable<Sha256Hash> {
    // A ZERO_HASH constant (32 zero bytes)
    public static final Sha256Hash ZERO_HASH = new Sha256Hash(new byte[32]);

    private final byte[] bytes;

    private Sha256Hash(byte[] bytes) {
        this.bytes = bytes;
    }

    // Create a hash from input bytes (single SHA-256)
    public static Sha256Hash create(byte[] input) {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = md.digest(input);
            return new Sha256Hash(hash);
        } catch (java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    // Create a hash by applying SHA-256 twice (double hash)
    public static Sha256Hash createDouble(byte[] input) {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-256");
            byte[] first = md.digest(input);
            byte[] second = md.digest(first);
            return new Sha256Hash(second);
        } catch (java.security.NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    // Hash code (based on contents)
    @Override
    public int hashCode() {
        int result = 1;
        for (byte b : bytes) {
            result = 31 * result + (b & 0xFF);
        }
        return result;
    }

    // Equality based on contents
    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Sha256Hash)) return false;
        Sha256Hash other = (Sha256Hash) o;
        return java.util.Arrays.equals(this.bytes, other.bytes);
    }

    // Convert to BigInteger (positive)
    public java.math.BigInteger toBigInteger() {
        return new java.math.BigInteger(1, bytes);
    }

    // Hex string representation
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder(bytes.length * 2);
        for (byte b : bytes) {
            String hex = Integer.toHexString(b & 0xFF);
            if (hex.length() == 1) sb.append('0');
            sb.append(hex);
        }
        return sb.toString();
    }

    // Duplicate (return a new copy of the hash bytes)
    public Sha256Hash duplicate() {
        return new Sha256Hash(bytes.clone());
    }

    // Lexicographic comparison of hash bytes
    @Override
    public int compareTo(Sha256Hash other) {
        int len = Math.min(this.bytes.length, other.bytes.length);
        for (int i = 0; i < len; i++) {
            int a = this.bytes[i] & 0xFF;
            int b = other.bytes[i] & 0xFF;
            if (a != b) return Integer.compare(a, b);
        }
        return Integer.compare(this.bytes.length, other.bytes.length);
    }

    // Get raw bytes
    public byte[] getBytes() {
        return bytes;
    }

    // Convenience method: hash the entire file contents (in memory)
    public static Sha256Hash hashFileContents(java.nio.file.Path path) {
        try {
            byte[] content = java.nio.file.Files.readAllBytes(path); // reads whole file into memory
            return create(content);
        } catch (java.io.IOException e) {
            throw new RuntimeException(e);
        }
    }
}

Use example:
- To hash a small file: Sha256Hash hash = Sha256Hash.hashFileContents(java.nio.file.Paths.get("path/to/file"));
- To get hex: hash.toString()
- To get bytes: hash.getBytes()
